const durations = { new_patient: 45, follow_up: 30, checkup: 30, urgent: 30 };
const body = $json.body;
const visitType = body.visit_type || 'follow_up';
const duration = durations[visitType] || 30;

// Force the requested time to be interpreted as Asia/Karachi local time
let rawDatetime = body.requested_datetime;
if (!/[+-]\d\d:\d\d$|Z$/.test(rawDatetime)) {
  rawDatetime = rawDatetime + '+05:00';
}
const start = new Date(rawDatetime);
const end = new Date(start.getTime() + duration * 60000);


return [{ json: { ...body, duration_minutes: duration, start_iso: start.toISOString(), end_iso: end.toISOString() } }];

