const durations = { new_patient: 45, follow_up: 30, checkup: 30, urgent: 30 };
const visitType = $json.visit_type || 'follow_up';
const duration = durations[visitType] || 30;

let rawDatetime = $('Intent Router').first().json.body.requested_datetime;
if (!/[+-]\d\d:\d\d$|Z$/.test(rawDatetime)) {
  rawDatetime = rawDatetime + '+05:00';
}
const start = new Date(rawDatetime);
const end = new Date(start.getTime() + duration * 60000);


return [{ json: { ...$json, duration_minutes: duration, start_iso: start.toISOString(), end_iso: end.toISOString() } }];

const candidates = $('Code in JavaScript(checking_available slots)').item.json.candidate_slots;
const busyEvents = $input.all().map(i => i.json).filter(e => e.start && e.end);

const free = candidates.filter(slot => {
  const s = new Date(slot.start_iso).getTime();
  const e = new Date(slot.end_iso).getTime();
  return !busyEvents.some(evt => {
    const bs = new Date(evt.start.dateTime).getTime();
    const be = new Date(evt.end.dateTime).getTime();
    return s < be && e > bs; // overlap check
  });
});

return [{ json: { available_slots: free.slice(0, 3) } }];

const durations = { new_patient: 45, follow_up: 30, checkup: 30, urgent: 30 };
const visitType = $json.body.visit_type || 'follow_up';
const duration = durations[visitType] || 30;
const date = $json.body.requested_date; // "2026-08-01"

const slots = [];
let hour = 9, min = 0;
while (hour < 17) {
  const start = new Date(`${date}T${String(hour).padStart(2,'0')}:${String(min).padStart(2,'0')}:00+05:00`); // <- +05:00 forces Asia/Karachi
  const end = new Date(start.getTime() + duration * 60000);
  slots.push({ start_iso: start.toISOString(), end_iso: end.toISOString() });
  min += duration;
  if (min >= 60) { hour += Math.floor(min/60); min = min % 60; }
}
return [{ json: { ...$json.body, candidate_slots: slots } }];
